export function getSignPlacement(planet: string, sign: string): PlacementContent | null {
  return SIGN_PLACEMENTS[`planet:${planet.toLowerCase()}:${sign.toLowerCase()}`] ?? null;
}

export interface VoiceContent {
  traditional: string;
  evolutionary: string;
  developmental: string;
  aphorism?: string;
  cycles?: [string, string][];
}

export function getPlacementContent(planet: string, sign: string): VoiceContent | null {
  const p = getSignPlacement(planet, sign);
  if (!p) return null;
  return { traditional: p.traditional, evolutionary: p.evolutionary, developmental: p.developmental };
}

export const SIGN_SLUGS = [
  'aries', 'taurus', 'gemini', 'cancer', 'leo', 'virgo',
  'libra', 'scorpio', 'sagittarius', 'capricorn', 'aquarius', 'pisces',
] as const;

export type SignSlug = typeof SIGN_SLUGS[number];
